const deadCellsToCheck = new Set();
for (const [x, y] of grid) {
  forEachOrthogonalNeighbor(x, y, (nx, ny) => {
    if (!liveCells.has(`${nx},${ny}`)) {
      deadCellsToCheck.add(`${nx},${ny}`);
    }
  });
}

