const isSurvivalPattern = (grid: Array<[number, number]>): boolean => {
  if (grid.length !== 3) return false;
  // Check for vertical line pattern: three cells at same x, consecutive y
  const sorted = [...grid].sort((a, b) => a[1] - b[1]);
  return (
    sorted[0][0] === sorted[1][0] &&
    sorted[1][0] === sorted[2][0] &&
    sorted[1][1] === sorted[0][1] + 1 &&
    sorted[2][1] === sorted[1][1] + 1
  );
};

